/* eslint-disable react-refresh/only-export-components */
import { createContext, useContext, useState, useEffect } from "react";
import { loginUser as apiLoginUser, logoutUser as apiLogoutUser, registerUser as apiRegisterUser, loginGuest as apiLoginGuest } from '../api/userApi';
import { useNavigate } from "react-router-dom";

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(false);
  }, []);

  // LOGIN
  const loginUser = async (credentials) => {
    const { data } = await apiLoginUser(credentials);
    setUser(data.data);
    navigate("/rooms"); // redirect after login
  };

  // LOGIN AS GUEST
  const loginAsGuest = async () => {
    try {
      setLoading(true);
      const { data } = await apiLoginGuest();
      setUser(data.data);
      navigate("/rooms"); // redirect to Dashboard/Lobby
    } catch (error) {
      throw error;
    } finally {
      setLoading(false);
    }
  };

  // LOGOUT
  const logout = async () => {
    await apiLogoutUser();
    setUser(null);
    navigate("/login");
  };

  // REGISTER
  const register = async (credentials) => {
    const { data } = await apiRegisterUser(credentials);
    setUser(data.data);
    navigate("/rooms");
  };

  return (
    <AuthContext.Provider
      value={{ user, loading, loginUser, logout, register, loginAsGuest }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

